import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "../../../../../etc/passwd";

        String basePath = "/home/user/files/";
        String filePath = Paths.get(basePath, userInput).normalize().toString();

        if (!filePath.startsWith(basePath)) {
            System.err.println("Access to files outside of base directory is not allowed.");
            return;
        }

        try {
            File file = new File(filePath);
            BufferedReader reader = new BufferedReader(new FileReader(file));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
            reader.close();
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

